class Solution {
    public int countLargestGroup(int n) {
        int[] count = new int[40];
        int maxCount = 0;
        for (int i = 1; i <= n; i++) {
            int sum = sumDigits(i);
            count[sum]++;
            maxCount = Math.max(maxCount, count[sum]);
        }
        int result = 0;
        for (int c : count) {
            if (c == maxCount) {
                result++;
            }
        }
        return result;
    }
    private int sumDigits(int num) {
        int sum = 0;
        while (num > 0) {
            sum += num % 10;
            num /= 10;
        }
        return sum;
    }
}
